        return float("nan")

    dt = 1.0 / fs
    duration = len(velocity) * dt
    v_peak = np.max(np.abs(velocity))
    if v_peak == 0:
        return float("-inf")

    jerk = np.diff(velocity, 2) / (dt**2)
    scale = (duration**3) / (v_peak**2 + EPS)
    dj = -scale * np.sum(jerk**2) * dt
    return float(np.log(np.abs(dj) + 1e-8))


